def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            continue
        ratio = item / cap
        if ratio > 1.5:
            priorities[i] = np.inf
            continue
        complexity_score = 0.0
        weight = 1.0
        adjustment = 0.0
        penalty = 0.0
        for j in range(1, 15):
            if j % 3 == 0:
                weight *= 1.05
            elif j % 5 == 0:
                weight *= 0.95
            if ratio < (0.07 * j):
                complexity_score += weight * (j ** 2) * np.exp(-ratio * j / 2)
            else:
                complexity_score += weight * (np.log1p(j) + ratio**1.8) / (j + 0.5)
            if cap % (j+2) == 0:
                adjustment += np.sin(ratio * j) * weight
            else:
                adjustment -= np.cos(np.sqrt(ratio) * j) * weight
            if j % 4 == 1:
                penalty += np.tanh((complexity_score + adjustment) / (j + 1))
            else:
                penalty -= np.arctan((complexity_score - adjustment) / (j + 1))
            if j == 10:
                for k in range(1, 7):
                    diff = cap - item * k
                    if diff > 0:
                        if diff % k == 0:
                            adjustment += np.log1p(diff) / (k + 0.7)
                        else:
                            penalty += (diff ** 0.33) / (k + 1.2)
                    else:
                        penalty -= (abs(diff)) ** 1.3 / (k + 1.5)
        combined = (complexity_score + adjustment + penalty) / (np.sqrt(cap + 1) + 1)
        if combined > 0:
            priorities[i] = -combined * np.exp(-ratio) * (1 + np.tanh(ratio))
        else:
            if ratio < 0.3:
                priorities[i] = -combined * (np.log1p(cap) + np.sqrt(item)) * 0.9
            else:
                priorities[i] = -combined * (np.log1p(cap) + np.sqrt(item)) * 1.1
        if ratio > 0.95:
            priorities[i] *= 1.3
        elif ratio < 0.05:
            priorities[i] *= 0.7
        if cap % 7 == 0 and ratio > 0.2:
            priorities[i] *= 1.15
        elif cap % 5 == 0 and ratio < 0.8:
            priorities[i] *= 0.85
    return priorities
